import { useState, useEffect, useRef, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Heart, Gift, Music, Mail, ChevronRight, Star } from "lucide-react";

const PHOTOS = [
  "data:image/jpeg;base64,",
  "data:image/jpeg;base64,",
  "data:image/jpeg;base64,",
  "data:image/jpeg;base64,",
  "data:image/jpeg;base64,",
  "data:image/jpeg;base64,",
  "data:image/jpeg;base64,",
  "data:image/jpeg;base64,",
  "data:image/jpeg;base64,",
  "data:image/jpeg;base64,",
];

const CAPTIONS = [
  "Every moment with you feels like home 💜",
  "You make every adventure worth it 🌟",
  "My favourite smile in the whole world 🌸",
  "Here's to all our crazy memories ✨",
  "Two goofballs, one beautiful story 💫",
  "Mountains, valleys — anywhere with you 🌄",
  "The way you dance into my heart 💃",
  "Dressed up & showing off, as always 👑",
  "College days & silly selfies — I love it 🌿",
  "Looking at you like this, always 💜",
];

// ─── Confetti ───────────────────────────────────────────────
function Confetti({ count = 80 }) {
  const pieces = Array.from({ length: count }, (_, i) => ({
    id: i,
    x: Math.random() * 100,
    delay: Math.random() * 2,
    dur: 2.5 + Math.random() * 2,
    color: ["#c084fc","#e879f9","#f0abfc","#818cf8","#fcd34d","#f9a8d4","#86efac"][Math.floor(Math.random() * 7)],
    size: 6 + Math.random() * 8,
    rotate: Math.random() * 360,
  }));
  return (
    <div className="fixed inset-0 pointer-events-none overflow-hidden z-50">
      {pieces.map((p) => (
        <motion.div
          key={p.id}
          className="absolute rounded-sm"
          style={{ left: `${p.x}%`, top: -20, width: p.size, height: p.size, backgroundColor: p.color, rotate: p.rotate }}
          animate={{ y: ["0vh", "110vh"], rotate: [p.rotate, p.rotate + 720], opacity: [1, 1, 0] }}
          transition={{ duration: p.dur, delay: p.delay, ease: "easeIn" }}
        />
      ))}
    </div>
  );
}

// ─── Floating Hearts bg ──────────────────────────────────────
function FloatingHearts() {
  const hearts = Array.from({ length: 18 }, (_, i) => ({
    id: i,
    x: Math.random() * 100,
    delay: Math.random() * 5,
    dur: 6 + Math.random() * 6,
    size: 10 + Math.random() * 20,
    opacity: 0.1 + Math.random() * 0.25,
  }));
  return (
    <div className="fixed inset-0 pointer-events-none overflow-hidden z-0">
      {hearts.map((h) => (
        <motion.div
          key={h.id}
          className="absolute text-purple-300"
          style={{ left: `${h.x}%`, bottom: -40, fontSize: h.size, opacity: h.opacity }}
          animate={{ y: [0, -window.innerHeight - 60] }}
          transition={{ duration: h.dur, delay: h.delay, repeat: Infinity, ease: "linear" }}
        >
          ♥
        </motion.div>
      ))}
    </div>
  );
}

// ─── PHASE 1: Entry ──────────────────────────────────────────
function PhaseEntry({ onEnter }) {
  const [btnPos, setBtnPos] = useState({ x: 0, y: 0 });
  const [dodgeCount, setDodgeCount] = useState(0);
  const [text, setText] = useState("Happy Birthday, Riya! 🎂");
  const maxDodges = 4;

  const dodge = useCallback(() => {
    if (dodgeCount >= maxDodges) return;
    const newCount = dodgeCount + 1;
    setDodgeCount(newCount);
    const x = (Math.random() - 0.5) * 260;
    const y = (Math.random() - 0.5) * 160;
    setBtnPos({ x, y });
    const msgs = [
      "Not so fast! 😈",
      "Earn your surprise!",
      "Almost... not yet! 🙈",
      "Okay FINE, come here! 💜",
    ];
    setText(msgs[newCount - 1] || "Happy Birthday, Riya! 🎂");
  }, [dodgeCount]);

  const canClick = dodgeCount >= maxDodges;

  return (
    <div className="min-h-screen flex flex-col items-center justify-center relative overflow-hidden"
      style={{ background: "linear-gradient(135deg, #1e1033 0%, #2d1b69 40%, #1a0a3e 100%)" }}>
      <FloatingHearts />
      {/* Stars */}
      {Array.from({ length: 40 }).map((_, i) => (
        <motion.div key={i} className="absolute rounded-full bg-white"
          style={{ left: `${Math.random()*100}%`, top: `${Math.random()*100}%`, width: 2+Math.random()*3, height: 2+Math.random()*3 }}
          animate={{ opacity: [0.2, 1, 0.2] }}
          transition={{ duration: 2+Math.random()*3, repeat: Infinity, delay: Math.random()*3 }}
        />
      ))}

      <motion.div initial={{ opacity: 0, y: -40 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 1 }}
        className="text-center z-10 px-6">
        <motion.div className="text-7xl mb-4" animate={{ rotate: [0, 15, -15, 0] }} transition={{ repeat: Infinity, duration: 2 }}>🎂</motion.div>
        <h1 className="text-5xl font-bold mb-3 text-transparent bg-clip-text"
          style={{ backgroundImage: "linear-gradient(90deg, #e879f9, #c084fc, #818cf8)", fontFamily: "'Georgia', serif" }}>
          Happy Birthday
        </h1>
        <h2 className="text-6xl font-bold text-white mb-2" style={{ fontFamily: "'Georgia', serif", textShadow: "0 0 30px #c084fc" }}>
          Riya 💜
        </h2>
        <p className="text-purple-300 text-xl mb-12 mt-4" style={{ fontFamily: "Georgia, serif" }}>{text}</p>

        <motion.div style={{ x: btnPos.x, y: btnPos.y }} transition={{ type: "spring", stiffness: 300, damping: 15 }}>
          <motion.button
            onHoverStart={!canClick ? dodge : undefined}
            onTouchStart={!canClick ? dodge : undefined}
            onClick={canClick ? onEnter : dodge}
            whileHover={canClick ? { scale: 1.08 } : {}}
            whileTap={canClick ? { scale: 0.95 } : {}}
            className="px-10 py-4 rounded-full text-white font-semibold text-xl shadow-2xl cursor-pointer"
            style={{ background: canClick ? "linear-gradient(135deg, #9333ea, #7c3aed)" : "linear-gradient(135deg, #e879f9, #9333ea)",
              boxShadow: "0 0 30px rgba(192,132,252,0.5)", fontFamily: "Georgia, serif" }}>
            {canClick ? "✨ Open Your Surprise ✨" : "Enter →"}
          </motion.button>
        </motion.div>
        {dodgeCount > 0 && dodgeCount < maxDodges && (
          <p className="text-purple-400 text-sm mt-6">Attempts: {dodgeCount}/{maxDodges} 😏</p>
        )}
      </motion.div>

      {/* Balloons */}
      {["🎈","🎈","🎀","🎈","🎈"].map((b, i) => (
        <motion.div key={i} className="absolute text-4xl bottom-0"
          style={{ left: `${10 + i * 20}%` }}
          animate={{ y: [0, -30, 0], rotate: [0, 5, -5, 0] }}
          transition={{ duration: 2.5 + i * 0.4, repeat: Infinity, delay: i * 0.3 }}>
          {b}
        </motion.div>
      ))}
    </div>
  );
}

// ─── PHASE 2: Mystery Box ────────────────────────────────────
function PhaseBox({ onOpen }) {
  const [opened, setOpened] = useState(false);
  const [showConfetti, setShowConfetti] = useState(false);

  const handleOpen = () => {
    if (opened) return;
    setOpened(true);
    setShowConfetti(true);
    setTimeout(() => { onOpen(); }, 2000);
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center relative overflow-hidden"
      style={{ background: "linear-gradient(135deg, #13002b 0%, #1e0050 50%, #2d0060 100%)" }}>
      {showConfetti && <Confetti count={100} />}
      <FloatingHearts />

      <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ duration: 0.8 }} className="text-center z-10 px-6">
        <motion.p className="text-purple-300 text-lg mb-8" style={{ fontFamily: "Georgia, serif" }}
          animate={{ opacity: [0.6, 1, 0.6] }} transition={{ repeat: Infinity, duration: 2 }}>
          ✨ Touch the box to see what's inside... ✨
        </motion.p>

        <motion.div onClick={handleOpen} className="cursor-pointer select-none relative inline-block"
          whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}>
          {/* Box */}
          <motion.div className="relative"
            animate={opened ? { scale: [1, 1.3, 0], rotate: [0, 15, -15, 0], opacity: [1, 1, 0] }
              : { y: [0, -10, 0] }}
            transition={opened ? { duration: 0.8 } : { repeat: Infinity, duration: 2 }}>
            {/* Lid */}
            <motion.div className="w-48 h-12 rounded-t-lg mx-auto relative z-20 flex items-center justify-center"
              style={{ background: "linear-gradient(135deg, #7c3aed, #9333ea)" }}
              animate={opened ? { y: -80, opacity: 0 } : {}}
              transition={{ duration: 0.5 }}>
              <div className="absolute top-0 left-1/2 -translate-x-1/2 w-6 h-8 rounded-b-full"
                style={{ background: "#fcd34d" }} />
              <div className="absolute top-0 left-0 right-0 h-1 rounded-t-lg"
                style={{ background: "linear-gradient(90deg, transparent, rgba(255,255,255,0.3), transparent)" }} />
            </motion.div>
            {/* Body */}
            <div className="w-56 h-44 rounded-b-xl relative -mt-1 flex items-center justify-center overflow-hidden"
              style={{ background: "linear-gradient(135deg, #6d28d9, #7c3aed)", boxShadow: "0 20px 60px rgba(109,40,217,0.6), inset 0 1px 0 rgba(255,255,255,0.2)" }}>
              {/* Ribbon vertical */}
              <div className="absolute inset-y-0 left-1/2 -translate-x-1/2 w-5"
                style={{ background: "linear-gradient(180deg, #fcd34d, #f59e0b)" }} />
              {/* Ribbon horizontal */}
              <div className="absolute inset-x-0 top-1/2 -translate-y-1/2 h-5"
                style={{ background: "linear-gradient(90deg, #fcd34d, #f59e0b)" }} />
              {/* Bow */}
              <div className="absolute -top-3 left-1/2 -translate-x-1/2 text-3xl z-30">🎀</div>
              {!opened && <Gift size={40} className="text-yellow-300 relative z-10" />}
              {opened && (
                <motion.div initial={{ scale: 0 }} animate={{ scale: [0, 1.5, 1] }} transition={{ duration: 0.5 }}
                  className="text-5xl relative z-10">💜</motion.div>
              )}
            </div>
          </motion.div>
        </motion.div>

        {!opened && (
          <motion.p className="text-purple-400 text-sm mt-8" style={{ fontFamily: "Georgia, serif" }}
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 1 }}>
            Tap the gift 🎁
          </motion.p>
        )}
        {opened && (
          <motion.p className="text-pink-300 text-xl mt-8 font-semibold" style={{ fontFamily: "Georgia, serif" }}
            initial={{ opacity: 0, scale: 0.5 }} animate={{ opacity: 1, scale: 1 }}>
            💫 A little something for you... 💫
          </motion.p>
        )}
      </motion.div>
    </div>
  );
}

// ─── PHASE 3: Memory Lane ────────────────────────────────────
function PhaseMemory({ onDone }) {
  const [current, setCurrent] = useState(0);
  const [started, setStarted] = useState(false);

  useEffect(() => {
    if (!started) { setTimeout(() => setStarted(true), 500); return; }
    if (current >= PHOTOS.length) { setTimeout(onDone, 1000); return; }
    const t = setTimeout(() => setCurrent((c) => c + 1), 4500);
    return () => clearTimeout(t);
  }, [current, started, onDone]);

  if (!started) return null;

  return (
    <div className="min-h-screen flex flex-col items-center justify-center relative overflow-hidden"
      style={{ background: "linear-gradient(135deg, #0f0020 0%, #1a0040 100%)" }}>
      <FloatingHearts />
      <div className="relative z-10 w-full max-w-sm mx-auto px-4 text-center">
        <motion.h2 className="text-2xl font-bold text-purple-300 mb-6" style={{ fontFamily: "Georgia, serif" }}
          initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
          💜 Memory Lane 💜
        </motion.h2>

        <div className="relative">
          <AnimatePresence mode="wait">
            {current < PHOTOS.length && (
              <motion.div key={current}
                initial={{ opacity: 0, scale: 0.88 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 1.04 }}
                transition={{ duration: 0.7 }}>
                {/* Elegant frame — adapts to photo's natural size */}
                <div className="relative rounded-2xl overflow-hidden"
                  style={{ border: "3px solid rgba(192,132,252,0.5)", boxShadow: "0 0 40px rgba(192,132,252,0.3), 0 0 80px rgba(168,85,247,0.15)", display: "inline-block", width: "100%" }}>
                  <img
                    src={PHOTOS[current]}
                    alt={`Memory ${current + 1}`}
                    style={{ width: "100%", height: "auto", maxHeight: "72vh", objectFit: "contain", display: "block" }}
                  />
                  {/* Overlay gradient — only bottom 40% so caption is readable */}
                  <div className="absolute inset-0"
                    style={{ background: "linear-gradient(to top, rgba(15,0,32,0.88) 0%, rgba(15,0,32,0.25) 38%, transparent 60%)", pointerEvents: "none" }} />
                  {/* Corner hearts */}
                  <div className="absolute top-3 right-3 text-pink-400 text-xl opacity-70">♥</div>
                  <div className="absolute top-3 left-3 text-purple-400 text-xl opacity-70">♥</div>
                  {/* Caption overlaid at bottom */}
                  <motion.div className="absolute bottom-0 left-0 right-0 p-4 text-center"
                    initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.5 }}>
                    <p className="text-white text-sm font-medium leading-snug" style={{ fontFamily: "Georgia, serif", textShadow: "0 2px 8px rgba(0,0,0,0.9)" }}>
                      {CAPTIONS[current]}
                    </p>
                    <p className="text-purple-400 text-xs mt-1">{current + 1} / {PHOTOS.length}</p>
                  </motion.div>
                </div>
              </motion.div>
            )}
            {current >= PHOTOS.length && (
              <motion.div key="done" initial={{ opacity: 0, scale: 0.8 }} animate={{ opacity: 1, scale: 1 }}
                className="flex items-center justify-center py-20">
                <div className="text-center">
                  <div className="text-6xl mb-4">💜</div>
                  <p className="text-white text-xl" style={{ fontFamily: "Georgia, serif" }}>So many beautiful memories...</p>
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        {/* Progress dots */}
        <div className="flex justify-center gap-2 mt-6">
          {PHOTOS.map((_, i) => (
            <div key={i} className="rounded-full transition-all duration-300"
              style={{ width: i === current ? 20 : 8, height: 8,
                background: i < current ? "#9333ea" : i === current ? "#e879f9" : "rgba(192,132,252,0.3)" }} />
          ))}
        </div>
      </div>
    </div>
  );
}

// ─── Cake Layer Component ─────────────────────────────────────
function CakeLayer({ width, height, bg, shadow, drips, dripH, label, labelStyle, extras, rounded, sliceOut, sliceDelay }) {
  return (
    <div className="mx-auto relative" style={{ width, height }}>
      {/* Left half — stays */}
      <div className="absolute left-0 top-0 h-full overflow-hidden" style={{ width: "50%", borderRadius: rounded === "top" ? "1rem 0 0 0" : rounded === "bottom" ? "0 0 0 1rem" : 0, background: bg, boxShadow: shadow }}>
        <div className="absolute inset-x-0 top-0 h-5" style={{ background: "rgba(255,255,255,0.15)" }} />
        {drips.slice(0, Math.floor(drips.length / 2)).map((x) => (
          <div key={x} className="absolute top-0 rounded-b-full" style={{ left: `${x * 2}%`, width: 13, height: dripH, background: "rgba(255,255,255,0.42)" }} />
        ))}
        {extras}
        {label && <p className="absolute inset-0 flex items-center justify-center text-white font-bold" style={{ fontFamily: "Georgia, serif", ...labelStyle }}>{label}</p>}
      </div>

      {/* Right half — flies off when sliceOut */}
      <motion.div className="absolute right-0 top-0 h-full overflow-hidden"
        style={{ width: "50%", borderRadius: rounded === "top" ? "0 1rem 0 0" : rounded === "bottom" ? "0 0 1rem 0" : 0, background: bg, transformOrigin: "bottom right" }}
        animate={sliceOut ? { x: [0, 20, 90], rotate: [0, 8, 25], opacity: [1, 1, 0], y: [0, -10, 30] } : { x: 0, rotate: 0, opacity: 1 }}
        transition={sliceOut ? { duration: 0.8, delay: sliceDelay, ease: "easeIn" } : {}}>
        <div className="absolute inset-x-0 top-0 h-5" style={{ background: "rgba(255,255,255,0.15)" }} />
        {drips.slice(Math.floor(drips.length / 2)).map((x) => (
          <div key={x} className="absolute top-0 rounded-b-full" style={{ left: `${(x - 50) * 2}%`, width: 13, height: dripH, background: "rgba(255,255,255,0.42)" }} />
        ))}
        {extras}
        {label && <p className="absolute inset-0 flex items-center justify-center text-white font-bold" style={{ fontFamily: "Georgia, serif", ...labelStyle }}>{label}</p>}
      </motion.div>

      {/* Cut gap line */}
      {sliceOut && (
        <motion.div className="absolute top-0 h-full" style={{ left: "50%", width: 3, transform: "translateX(-50%)", background: "rgba(255,255,255,0.85)", boxShadow: "0 0 12px rgba(255,255,255,0.9), 0 0 24px rgba(232,121,249,0.6)", zIndex: 10 }}
          initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ duration: 0.2 }} />
      )}
    </div>
  );
}

// ─── PHASE 4: Cake Cutting ───────────────────────────────────
function PhaseCake({ onDone }) {
  const [cutting, setCutting] = useState(false);
  const [cut, setCut] = useState(false);
  const [playing, setPlaying] = useState(false);

  const handleCut = () => {
    if (cut) return;
    setCutting(true);
    setTimeout(() => { setCut(true); setPlaying(true); }, 500);
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center relative overflow-hidden py-8"
      style={{ background: "linear-gradient(135deg, #0d001f 0%, #1a0040 50%, #0d001f 100%)" }}>
      <FloatingHearts />
      {cut && <Confetti count={80} />}

      <div className="relative z-10 text-center px-4 w-full max-w-md mx-auto flex flex-col items-center">

        {/* ── Header — always above candles, never overlaps cake ── */}
        <AnimatePresence mode="wait">
          {!cut ? (
            <motion.div key="pre" className="mb-2"
              initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }}>
              <h2 className="text-3xl font-bold text-transparent bg-clip-text"
                style={{ backgroundImage: "linear-gradient(90deg, #e879f9, #c084fc, #818cf8)", fontFamily: "Georgia, serif" }}>
                Happy Birthday
              </h2>
              <h1 className="text-4xl font-bold text-white"
                style={{ fontFamily: "Georgia, serif", textShadow: "0 0 30px #c084fc" }}>
                Riya 🎂
              </h1>
            </motion.div>
          ) : (
            <motion.div key="post" className="mb-2"
              initial={{ opacity: 0, scale: 0.6 }} animate={{ opacity: 1, scale: 1 }}
              transition={{ delay: 0.6, type: "spring", stiffness: 180 }}>
              <h2 className="text-3xl font-bold text-transparent bg-clip-text"
                style={{ backgroundImage: "linear-gradient(90deg, #fcd34d, #e879f9, #c084fc)", fontFamily: "Georgia, serif" }}>
                🎉 Happy 24th Birthday 🎉
              </h2>
              <p className="text-purple-300 text-lg" style={{ fontFamily: "Georgia, serif" }}>My dearest Riya 💜</p>
            </motion.div>
          )}
        </AnimatePresence>

        {/* ── Candles row — sits between header and cake ── */}
        <div className="flex justify-center gap-3 mb-1" style={{ marginTop: 8 }}>
          {Array.from({ length: 7 }).map((_, i) => (
            <motion.div key={i} className="text-2xl"
              animate={{ opacity: [1, 0.5, 1], scale: [1, 1.1, 1] }}
              transition={{ duration: 0.5 + i * 0.08, repeat: Infinity }}>
              🕯️
            </motion.div>
          ))}
        </div>

        {/* ── Cake body ── */}
        <div className="cursor-pointer" style={{ width: 300 }} onClick={handleCut}>
          <motion.div animate={cut ? {} : { y: [0, -5, 0] }} transition={{ repeat: Infinity, duration: 2.2 }}>

            {/* Top tier — "Happy" */}
            <CakeLayer
              width={190} height={90}
              bg="linear-gradient(180deg, #f0abfc, #d946ef, #a21caf)"
              shadow="0 6px 30px rgba(232,121,249,0.55)"
              drips={[4,12,20,28,36,44]} dripH={28}
              label="Happy"
              labelStyle={{ fontSize: 20, textShadow: "0 2px 8px rgba(0,0,0,0.5)", marginTop: 14 }}
              rounded="top"
              extras={null}
              sliceOut={cut} sliceDelay={0.05}
            />

            {/* Middle tier — "Birthday" */}
            <CakeLayer
              width={250} height={80}
              bg="linear-gradient(180deg, #a855f7, #7c3aed)"
              shadow="0 4px 20px rgba(168,85,247,0.4)"
              drips={[3,11,19,27,35,43,51]} dripH={25}
              label="Birthday"
              labelStyle={{ fontSize: 18, textShadow: "0 2px 8px rgba(0,0,0,0.5)", marginTop: 12 }}
              rounded=""
              extras={null}
              sliceOut={cut} sliceDelay={0.1}
            />

            {/* Bottom tier — "Riya" */}
            <CakeLayer
              width={300} height={110}
              bg="linear-gradient(180deg, #6d28d9, #4c1d95)"
              shadow="0 12px 40px rgba(76,29,149,0.7)"
              drips={[3,9,15,21,27,33,39,45]} dripH={30}
              label="✦ Riya ✦"
              labelStyle={{ fontSize: 16, letterSpacing: "0.1em", textShadow: "0 2px 8px rgba(0,0,0,0.5)" }}
              rounded="bottom"
              extras={
                <div className="absolute bottom-4 left-0 right-0 flex justify-center gap-1 px-3">
                  {Array.from({ length: 10 }).map((_, i) => (
                    <div key={i} className="rounded-full" style={{ width: 7, height: 7, background: "rgba(255,255,255,0.45)" }} />
                  ))}
                </div>
              }
              sliceOut={cut} sliceDelay={0.15}
            />
          </motion.div>
        </div>

        {/* ── Knife ── */}
        {!cut && (
          <motion.div className="mt-6 flex items-center justify-center gap-3 cursor-pointer"
            onClick={handleCut}
            whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.9 }}
            animate={cutting
              ? { x: [0, 30, 100], y: [0, -20, -40], rotate: [0, -30, -60], opacity: [1, 1, 0] }
              : { rotate: [-5, 5, -5] }}
            transition={cutting ? { duration: 0.5, ease: "easeIn" } : { repeat: Infinity, duration: 1.5 }}>
            <span className="text-4xl">🔪</span>
            <span className="text-purple-300 text-base" style={{ fontFamily: "Georgia, serif" }}>Tap to cut the cake!</span>
          </motion.div>
        )}

        {/* ── Post-cut UI ── */}
        {cut && (
          <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.9 }}
            className="mt-6 w-full">
            {playing && (
              <div className="flex items-center justify-center gap-2 mb-4">
                <Music size={20} className="text-purple-400" />
                <div className="flex gap-1 items-end h-8">
                  {Array.from({ length: 12 }).map((_, i) => (
                    <motion.div key={i} className="w-1.5 rounded-full bg-purple-400"
                      animate={{ height: [4, 8 + Math.random() * 20, 4] }}
                      transition={{ duration: 0.4 + Math.random() * 0.4, repeat: Infinity, delay: i * 0.05 }} />
                  ))}
                </div>
                <span className="text-purple-300 text-xs ml-1">♪ Happy Birthday ♪</span>
              </div>
            )}
            <motion.button onClick={onDone}
              className="mt-2 px-8 py-3 rounded-full text-white font-semibold text-base"
              style={{ background: "linear-gradient(135deg, #9333ea, #7c3aed)", boxShadow: "0 0 25px rgba(147,51,234,0.5)", fontFamily: "Georgia, serif" }}
              whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}
              animate={{ boxShadow: ["0 0 20px rgba(192,132,252,0.3)", "0 0 40px rgba(192,132,252,0.6)", "0 0 20px rgba(192,132,252,0.3)"] }}
              transition={{ duration: 2, repeat: Infinity }}>
              One Last Thing... →
            </motion.button>
          </motion.div>
        )}
      </div>
    </div>
  );
}

// ─── PHASE 5: Grand Finale ───────────────────────────────────
